                    )
                ),
            // 팔로우 수: 5분
            CacheNames.FOLLOW_COUNT to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(5)),
            // 좋아요 수: 1분 (변경 빈도 높음)
            CacheNames.LIKE_COUNT to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(1)),
            // 알림 설정: 30분
            CacheNames.NOTIFICATION_SETTING to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(30)),
            // 코드/카테고리: 1시간 (거의 변경 없음)
            CacheNames.CODE_TABLE to RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofHours(1)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(
                RedisCacheConfiguration.defaultCacheConfig()
                    .entryTtl(Duration.ofMinutes(5))  // 기본 TTL
                    .disableCachingNullValues()
            )
            .withInitialCacheConfigurations(cacheConfigs)
            .build()
    }
}

